// Loop through all incoming items
for (const item of $input.all()) {

  // 1. DATA EXTRACTION
  const data = item.json.body?.record || {};

  // 2. FORMATTING HELPERS
  const formatDate = (dateString) => {
    if (!dateString) return 'TBD';
    return new Date(dateString).toLocaleDateString('en-US', { 
      month: 'long', day: 'numeric', year: 'numeric' 
    });
  };

  const safeGet = (val, fallback = '') => {
    if (Array.isArray(val)) {
      const first = val[0];
      // Handle array of objects vs array of strings
      return (first && typeof first === 'object') ? (first.name || fallback) : (first || fallback);
    }
    return val || fallback;
  };

  const formatMultiLine = (text) => {
    if (!text) return '';
    return text.replace(/\n/g, '<br>');
  };

  // 3. PREPARE VARIABLES
  const submittedBy = safeGet(data['Submitted by'], 'Unknown');
  const vaName = safeGet(data['Virtual Assistant Name'], 'N/A');
  const reason = safeGet(data['Reason for Removal'], 'No reason provided.');
  const submissionDate = formatDate(data['Created']);
  const requestorEmail = safeGet(data["Requestor's Email"], 'N/A');

  // 4. HTML CONSTRUCTION
  const htmlContent = `
<!DOCTYPE html>
<html>
<head>
<style>
  html, body {
    margin: 0;
    padding: 0;
    background-color: #f4f6f8;
  }
  body { 
    font-family: Helvetica, Arial, sans-serif; 
    color: #333333; 
    line-height: 1.5; 
    font-size: 14px; 
  }
  .outer-wrapper {
    width: 100%;
    background-color: #f4f6f8;
    padding: 20px 0;
  }
  .container { 
    max-width: 650px; 
    margin: 0 auto; 
    border: 1px solid #e5e7eb; 
    border-radius: 8px; 
    padding: 30px; 
    background-color: #ffffff; 
    text-align: left;
  }
  .greeting { margin-bottom: 15px; font-size: 14px; }
  .intro-text { margin-bottom: 25px; font-size: 14px; }

  table { 
    width: 100%; 
    border-collapse: collapse; 
    margin-bottom: 25px; 
    border: 1px solid #e5e7eb; 
  }
  th { 
    background-color: #E8833A; 
    color: #ffffff; 
    padding: 12px; 
    text-align: center; 
    font-weight: 700;
    text-transform: uppercase; 
    font-size: 14px;
    letter-spacing: 0.5px;
  }
  td { 
    padding: 12px 15px; 
    border-bottom: 1px solid #e5e7eb; 
    vertical-align: top; 
    font-size: 14px;
  }
  .label-col { 
    width: 35%; 
    background-color: #f0f2f5; 
    color: #111827; 
    font-weight: 800; 
    border-right: 1px solid #e5e7eb;
  }
  .value-col { width: 65%; color: #374151; }

  .footer-note {
    background-color: #fff7ed;
    border-left: 5px solid #E8833A;
    padding: 15px 20px;
    margin-top: 10px;
    color: #4b5563;
    font-size: 14px;
  }
  .status-tag {
    color: #b91c1c;
    font-weight: 800;
  }
</style>
</head>
<body>

<table class="outer-wrapper" role="presentation" cellspacing="0" cellpadding="0">
  <tr>
    <td align="center">
      <div class="container">

        <div class="greeting">Hi <strong>Team</strong>,</div>
        <div class="intro-text">A Limbo removal request has been submitted by: <strong>${submittedBy}</strong></div>

        <table role="presentation">
          <tr>
            <th colspan="2">Removal Details</th>
          </tr>
          <tr>
            <td class="label-col">Virtual Assistant</td>
            <td class="value-col">${vaName}</td>
          </tr>
          <tr>
            <td class="label-col">Reason for Removal</td>
            <td class="value-col">${formatMultiLine(reason)}</td>
          </tr>
          <tr>
            <td class="label-col">Submitted Date</td>
            <td class="value-col">${submissionDate}</td>
          </tr>
          <tr>
            <td class="label-col">Requestor Email</td>
            <td class="value-col">${requestorEmail}</td>
          </tr>
        </table>

        <div class="footer-note">
          <strong>Note:</strong> ${vaName} is now tagged as <span class="status-tag">Inactive</span>.
        </div>

      </div>
    </td>
  </tr>
</table>

</body>
</html>
  `;

  item.json.email_html = htmlContent;
}

return $input.all();

